var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"크윽! 끝이 없잖아…!!","JPN":"くっ！　切りがない……！！","ENG":"Kgh! They just keep coming...!","TWN":"咳呃！沒完沒了……！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 거울이랑 가위바위보 하는 것도 아니고, 이러다가 이쪽이 먼저 나가떨어지겠어!","JPN":"鏡とジャンケンしてるみたいで、これじゃこっちが先にぐたぐたになるよ！","ENG":"Feels like playing rock-paper-scissors against a mirror. We'll be the ones dropping first at this rate!","TWN":"這可不是和鏡子玩剪刀石頭布，這樣下去我這邊會先撐不住的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"침착해라. 결국 무구의 힘에 깃댄 일시적인 침식 현상에 불과해.","JPN":"落ち着け。結局は武具の力に頼った一時的な侵食現象だ。","ENG":"Stay calm. This is just a temporary Counterside Effect caused by the Armament's power.","TWN":"冷靜點。這不過是暫時的侵蝕現象，最終會消散在武具的力量中。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그림자 전당과 달리 전투가 길어지더라도 현상이 악화되지는 않을 거야.","JPN":"影の殿堂とは違い、戦闘が長くなっても現象が悪化することはないだろう。","ENG":"Unlike the Shadow Palaces, the effect won't worsen even if the fight drags on.","TWN":"與暗影殿堂不同，即使戰鬥拖延，現象也不會惡化。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무구를 갖춘 도플갱어 침식체들은 내가 막겠다!","JPN":"武具を持っている侵食体は私が止める！","ENG":"I'll take care of the Doppelganger-types with weapons!","TWN":"我會阻止那些裝備武具的化身侵蝕體！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"상대적으로 약한 침식체들을 우선 공격하여, 수의 우위로 놈들을 밀어붙이도록!","JPN":"比較的弱い侵食体を優先的に攻撃し、数的優位でやつらを追い込むのだ！","ENG":"Everyone else, focus on the weaker ones! Push through with numbers!","TWN":"優先攻擊相對較弱的侵蝕體，以數量優勢壓制他們！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"적의 수가 줄어들고는 있으나, 다들 연전으로 지친 탓에 그 속도가 더디다.","JPN":"敵の数は減っているが、みんな連戦で疲れているため、その速度が徐々に低下している。","ENG":"The enemy's thinning out, but everyone's exhausted from constant combat. Progress is too slow.","TWN":"敵人的數量雖然在減少，但由於大家連續作戰疲憊不堪，速度變得緩慢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"시간을 소모한다면 길을 뚫을 수 있겠지만, 이런 소모전을 계속해서는…….","JPN":"時間をかければ道を開けることはできるはずだが、こんな消耗戦を続けては……","ENG":"We might break through if we hold out, but we can't keep up this attrition...","TWN":"如果耗費時間的話，雖然可以開闢道路，但這樣持續消耗戰的話……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"역시, 그 방법밖에 없나.","JPN":"やはり、あの方法しかないか。","ENG":"Looks like we don't have a choice.","TWN":"果然，只有那個辦法了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"6시 방향! 침식체 무리가 돌격합니다!!","JPN":"6時の方角！　侵食体の群れが突撃してきます！","ENG":"Six o'clock! A horde of C.O.s charging in!","TWN":"6點鐘方向！侵蝕體群正在衝鋒！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"진형을 갖추고 피해에 대비해! 내가 앞서 놈들을 흩트리겠다!","JPN":"陣形を整え、攻撃に備えろ！　私が先鋒でやつらを蹴散らす！","ENG":"Form ranks and brace for impact! I'll go ahead and break their line!","TWN":"準備陣型，做好防禦！我會先去擾亂它們！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오케이! 맡겨만 둬-!!","JPN":"オッケー！　任せてー！！","ENG":"Got it! Leave it to me!","TWN":"好的！交給我吧-！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부, 부단장? 갑자기 끼어들다니. 이게 무슨 짓인가?","JPN":"ふ、副団長？　いきなり割り込んでくるなんて。何をしている！","ENG":"D-Deputy? Why did you jump in?! What are you doing?","TWN":"副、副團長？突然插進來。這是幹什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"분하지만 지친 저희로서는 당신의 싸움에 도움이 될 수 없습니다.","JPN":"悔しいですが、疲れている私たちではあなたの力になれません。","ENG":"As much as I hate to admit it, we're too worn out to be of any use to your fight.","TWN":"雖然不甘心，但我們已經疲憊不堪，無法在戰鬥中幫助你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 단장님은 오롯이 그 남자와의 싸움에 전념하시죠.","JPN":"ですので、団長はあの男との戦いに専念してください。","ENG":"So please, focus everything you have on defeating him.","TWN":"所以團長你就專心與那個男人戰鬥吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그것이 저희가 승리할 수 있는 유일한 방법입니다.","JPN":"それが私たちが勝利できる唯一の方法です。","ENG":"That's the only way we can win.","TWN":"那是我們唯一能贏的方法。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무슨 소리를 하는 건가, 부단장!","JPN":"何を言っている、副団長！","ENG":"What are you saying, Deputy?!","TWN":"你在說什麼，副團長！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"도움이 안 된다니. 난 그런 생각은…!!","JPN":"力になれないなんて。私はそんなこと……！！","ENG":"You're not useless. I never thought that for a second...!","TWN":"說我沒幫上忙。我可不這麼想……！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"착각이 심하시군요, 단장님은!","JPN":"とんでもない勘違いです、団長！","ENG":"You're being delusional, Captain!","TWN":"你真是誤會了，團長！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"유구한 역사를 자랑해온 기사단이 단장님 한 분 없다고 무너질 것 같습니까?","JPN":"長い歴史を誇る騎士団が、団長がいないからって崩れると思っているのですか？","ENG":"Do you really think the Order, with its proud legacy, would fall without you?!","TWN":"擁有悠久歷史的騎士團會因為沒有團長而崩潰嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 저희를 지키실 필요는 없습니다!","JPN":"団長が私たちを守る必要はありません！","ENG":"You don't need to protect us!","TWN":"團長你不需要保護我們！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사단이, 당신을 지킬 겁니다!","JPN":"騎士団が、あなたを守ります！","ENG":"We'll be the ones protecting you!","TWN":"騎士團會保護你的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 병사들이 목숨을 걸고 저를 지켜주고 있으니까요.","JPN":"私の兵士たちが命をかけて守ってくれていますから。","ENG":"Because my soldiers are risking their lives to protect me.","TWN":"我的士兵們正在拼命保護我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저 또한 그들을 믿으니, 제가 불안에 떨 요소는 어디에도 없습니다.","JPN":"私もまた彼らのことを信頼していますので、不安がる理由などどこにもありません。","ENG":"And I trust them, so there's nothing for me to fear.","TWN":"我也相信他們，所以我沒有任何不安的理由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……미안하군. 내 스스로에게 엄격했던 나머지 그대에게 우려를 끼쳤어.","JPN":"……すまない。自分自身に厳しくしていたせいで、君を心配させてしまった。","ENG":"...Forgive me. I've been so hard on myself, I didn't realize I was worrying you.","TWN":"……抱歉。我對自己過於嚴格，以至於讓你擔心了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그대라면 이 전장을 믿고 맡길 수 있겠지.","JPN":"君にならこの戦場を安心して任せられる。","ENG":"But you, I can trust you to hold the line.","TWN":"如果是你的話，我可以放心地把這個戰場交給你。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아뇨. 저뿐만이 아닙니다.","JPN":"いいえ。私だけではありません。","ENG":"No. It's not just me.","TWN":"不，不只是我一個人。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"말하지 않았나요. <color=#ffd34c>기사단</color>이 단장님을 지킬 거라고.","JPN":"言ったはずです。<color=#ffd34c>騎士団</color>が団長を守ると。","ENG":"Didn't I say it already? The <color=#ffd34c>Order</color> will protect you, Captain.","TWN":"我不是說過嗎。<color=#ffd34c>騎士團</color>會保護團長的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으음… 분하지만 부단장 말이 맞으려나?","JPN":"うーん……悔しいけど副団長の言うとおりかな。","ENG":"Mm... As much as I hate to admit it, she might be right.","TWN":"嗯…雖然不甘心，但副團長說得對嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"멋진 척 다했는데 단장이 우리 뒤치다꺼리하는 것도 좀 눈치 보인다고.","JPN":"カッコつけたのに、団長が私たちの面倒を見てくれるのもちょっとね。","ENG":"We were trying to look all cool, and now Captain's covering for us? That's kinda awkward.","TWN":"裝得再厲害，還是讓團長幫我們收拾殘局，有點不好意思啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"동의해요. 이렇게 된 이상, 저도 단장님이 최상의 상태를 유지하실 수 있도록 돕겠습니다!","JPN":"私もそう思います。こうなった以上、私も団長が最高の体調を維持できるように頑張ります！","ENG":"I agree. I'll do everything I can to help Captain maintain her best.","TWN":"同意。既然如此，我也會協助團長保持最佳狀態！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"마, 맞아요!","JPN":"そ、そうです！","ENG":"R-right!","TWN":"對，對啊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"제가 아무도 안 다치게 할 테니까, 단장님이 무리하실 필요 없어요!","JPN":"私が、誰も怪我しないようにしますから、団長が無理する必要はないですよ！","ENG":"I'll make sure no one gets hurt, so you don't have to overdo it, Captain!","TWN":"我會保護大家不受傷害，團長你不必勉強自己！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에, 에리어스? 위험하게 여긴 왜 온 거야?","JPN":"ア、アリウス？　なんでここに来たの、危険だって！","ENG":"A-Arius?! What are you doing here? It's dangerous!","TWN":"埃、埃里奧斯？這裡很危險，你為什麼來這裡？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"다들 저 때문에 고생하시는데… 어리다는 이유로 계속 보호받고 싶지 않아요.","JPN":"みんな私のせいで苦労しているのに……幼いって理由でずっと守られるばっかりじゃイヤなんです。","ENG":"Everyone's suffered because of me. I don't want to just be protected anymore.","TWN":"大家都因為我而辛苦了……我不想因為年幼而一直受到保護。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"남아있기 무서운 것도 있지만! 그, 그래도 저도 싸울 거예요!","JPN":"残ってるのが怖いって理由もあるんですけど！　で、でも私も戦います！","ENG":"I'm scared to stay here, but! I-I still want to fight!","TWN":"雖然留下來很可怕！但、但是我也會戰鬥的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저도 조디악 나이츠의 일원인 걸요!!","JPN":"私もゾディアックナイツの一員ですから！！","ENG":"I'm part of the Zodiac Knights too!","TWN":"我也是十二宮騎士的一員！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스. 너 진짜……","JPN":"アリウス。あなた……","ENG":"Arius...","TWN":"埃里奧斯。你真是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에휴, 모르겠다. 대신 내 뒤에 딱 달라붙어 있어야 해?","JPN":"ああ、もう。その代わり、ちゃんと私の後ろにいてよね。","ENG":"*Sigh* I give up. But you're sticking to my back, understand?","TWN":"哈啊，我也不想管了。不過你得緊緊跟在我後面喔？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L17_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네! 절대 민폐 안 끼칠게요!!","JPN":"はい！　絶対迷惑になりません！！","ENG":"Yes! I promise I won't get in the way!","TWN":"是的！我絕對不會連累你們的！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"한 가지 묻겠습니다, 단장님.","JPN":"一つ聞きましょう、団長。","ENG":"Captain. Let me ask you something.","TWN":"我只問一個問題，團長。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님께서는 그 남자를. 카란티시르를 이기실 수 있습니까?","JPN":"団長はあの男に。カランティシルに勝てるのですか？","ENG":"Do you believe you can defeat Carantisir?","TWN":"團長，你能打敗那個男人，卡蘭堤西爾嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……모르겠군.","JPN":"……わからない。","ENG":"...I don't know.","TWN":"……我不知道。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 그대들이 지켜보는 전장에서 질 생각은 없어.","JPN":"だが、君たちが見守っている戦場で負けるつもりはない。","ENG":"But I have no intention of losing. Not in front of all of you.","TWN":"但我不會在你們注視的戰場上認輸。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 지금은 그걸로 충분합니다.","JPN":"はい。今はそれで十分です。","ENG":"Then that's enough for now.","TWN":"是的。現在這樣就足夠了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠! 지금부터 규율에 따라, 각 파벌을 대표하는 기사의 결투를 진행하겠다!","JPN":"ゾディアックナイツ！　今から規律に基づき、各派閥を代表する騎士の決闘を行う！","ENG":"Zodiac Knights! From this moment forward, we commence a formal duel between faction champions!","TWN":"十二宮騎士！從現在開始，將按照規矩進行各派代表騎士的決鬥！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"별을 추종하는 기사로서, 그대들은 무엇을 맹세하는가!","JPN":"星の追従者たるもの、そなたらは何を誓うか！","ENG":"As knights who follow the stars, what do you vow?!","TWN":"作為追隨星辰的騎士，你們誓言什麼！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하나! 정당한 결투를 위해 그대의 가능성을 제외한 그 어떤 개입도 허락하지 않는다!","JPN":"一つ！　正々堂々たる決闘のため、そなたの可能性を除くどのような介入も許さん！","ENG":"I vow! No outside interference shall sully this rightful duel!","TWN":"為了公平決鬥，除了你的可能性之外，任何干預都不被允許！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L30_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"하나! 그대를 믿고 따름에, 우리의 창칼에 정의를 드높이리!","JPN":"一つ！　そなたを信頼し従うことにより、我々の武器に正義を掲げる！","ENG":"I vow! To trust you and raise the banner of justice with our blades!","TWN":"相信並追隨你，我們的槍劍將高舉正義！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L31_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"하나! 전력으로 깨부수고 오라고 응원한다!!","JPN":"一つ！　全力で勝って来いと応援する！！","ENG":"I vow! To smash them to pieces and cheer like hell!","TWN":"加油！全力以赴去打破它吧！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"하나! 동료의 승리를 믿고, 우리들의 긍지를 전장에 메아리치리!!","JPN":"一つ！　仲間の勝利を信じ、我々の誇りを戦場に轟かす！！","ENG":"I vow! To echo our pride across this battlefield with belief in our comrade's victory!","TWN":"相信同伴的勝利，讓我們的自豪在戰場上迴響！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……못 이기겠군. 역시, 부단장보다는 단장 자리에 어울리는 거 아닌가?","JPN":"……まったく。やはり、副団長よりは団長に向いているのではないか？","ENG":"...I give up. Honestly, Deputy, you'd make a better captain than me.","TWN":"……贏不了啊。果然，比起副團長，更適合團長的位置吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"기사들을 이끄는 것뿐이라면 적임자라 할만한 기사들이 여럿 있습니다.","JPN":"騎士を率いるだけなら、適任者と言えるような騎士は多いでしょう。","ENG":"There are plenty of knights qualified to lead the Order.","TWN":"如果只是帶領騎士的話，有很多騎士都可以勝任。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 우리에게 승리를 안겨줄 수 있는 분은 오직 당신뿐이에요, 에스테로사 경.","JPN":"ですが私たちを勝利へと導いてくれる人はあなただけです、エステロサ卿。","ENG":"But the only one who can bring us victory is you, Dame Esterosa.","TWN":"但是能為我們帶來勝利的人只有你，艾斯特洛索。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"가시죠, 단장님.","JPN":"行ってください、団長。","ENG":"Now go, Captain.","TWN":"請走吧，團長。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"지금까지 그래왔듯. 기사단이 당신을 위한 방패가 되겠습니다.","JPN":"今までそうであったように。騎士団があなたのための盾となります。","ENG":"Just like always, the Order will be your shield.","TWN":"如同至今為止一樣，騎士團將成為你的盾牌。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};